// Helper function to get string array for a language
inline const char* const* getStringArray(Language lang) {
  switch (lang) {
    case Language::ENGLISH:
      return i18n_strings::STRINGS_EN;
    default:
      return i18n_strings::STRINGS_EN;
  }
}

